#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define ll __int128
const int N=100005;
const ll inf=((ll)1e17)*((ll)1e17);
ll n,a[N],b[N],c[N],tim[N],fa[N],e[N],vis[N];
vector<int> g[N];
inline ll read() {
    ll x = 0, f = 1;
    char ch = getchar();
    while (ch < '0' || ch > '9') {
        if (ch == '-') f = -1;
        ch = getchar();
    }
    while (ch >= '0' && ch <= '9') {
        x = x * 10 + (ch - '0');
        ch = getchar();
    }
    return x * f;
}
inline void write(ll x) {
    if (x < 0) {
        putchar('-');
        x = -x;
    }
    if (x > 9) write(x / 10);
    putchar(x % 10 + '0');
}
struct node
{
	ll l,r;
	bool operator<(const node other) const
	{
		return l<other.l;
	}
} d[N];
void dfs(int u,int f)
{
	fa[u]=f;
	for(int i=0;i<g[u].size();i++)
	{
		int v=g[u][i];
		if(v==f)
		{
			continue;
		}
		dfs(v,u);
	}
}
ll fun(ll num,ll x,ll y)
{
	ll len=y-x+1;
	if(tim[num]<x) return len;
	if(tim[num]>y) return len*b[num]+(x+y)*len/2*c[num];
	return y-tim[num]+(tim[num]-x+1)*b[num]+(x+tim[num])*(tim[num]-x+1)/2*c[num];
}
bool check(ll x)
{
//	cout<<x<<"aaa:::"<<endl;
	memset(vis,0,sizeof(vis));
	for(int i=1;i<=n;i++)
	{
//		cout<<i<<endl;
		if(fun(i,1,x)<a[i]) return 0;
		ll l=1,r=n,mid;
		while(l<=r)
		{
			mid=(l+r)/2;
//			cout<<l<<" "<<r<<" "<<mid<<"  abcd"<<endl;
			if(fun(i,mid,x)>=a[i]) l=mid+1;
			else r=mid-1;
		}
		d[i]={l-1,i};
		e[i]=l-1;
	}
//	cout<<x<<"  ::ccc"<<endl;
	sort(d+1,d+1+n);
	vis[0]=1;
	ll cnt=0;
//	cout<<x<<"  ::bbb"<<endl;
	for(int i=1;i<=n;i++)
	{
		vector<ll> vv;
		ll tmp=d[i].r;
		while(!vis[tmp])
		{
//			cout<<tmp<<endl;
			vv.push_back(tmp);
			vis[tmp]=1;
			tmp=fa[tmp];
		}
		for(int j=vv.size()-1;j>=0;j--)
		{
			cnt++;
			if(e[vv[j]]<cnt) return 0;
		}
	}
	return 1;
}
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
//	freopen(".in","r",stdin);
//	freopen(".out","w",stdout);
	n=read();
	for(int i=1;i<=n;i++)
	{
		a[i]=read();
		b[i]=read();
		c[i]=read();
	}
	for(int i=1;i<n;i++)
	{
		int u,v;
		u=read();
		v=read();
		g[u].push_back(v);
		g[v].push_back(u);
	}
//	cout<<"aaa"<<endl;
	dfs(1,0);
//	cout<<"bbb"<<endl;
	for(int i=1;i<=n;i++)
	{
		if(c[i]>=0) tim[i]=inf;
		else tim[i]=(1-b[i])/c[i];
	}
	ll l=n,r=1e9,mid;
//	cout<<"ccc"<<endl;
	while(l<=r)
	{
		mid=(l+r)/2;
		if(check(mid)) r=mid-1;
		else l=mid+1;
	}
	write(l);
	return 0;
}
